var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"큭, 생각보다 저항이 거칠군.","JPN":"くっ、予想以上に抵抗が激しい。","ENG":"Kgh, they are resisting more than I had anticipated.","TWN":"唔，沒想到你們竟然如此頑強抵抗。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 이제 어떻게 할 거야? 경기 시간, 앞으로 40초 밖에 안 남았다고!","JPN":"副団長！　どうするつもり？　試合時間、あと40秒しかないよ！","ENG":"Deputy! What do we do now? There's only 40 seconds left on the clock!","TWN":"副團長！現在怎麼辦？時間只剩40秒！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 부단장님!! 시간이 없어요!!","JPN":"フィオネ副団長！！　時間がありません！！","ENG":"Deputy Fione!!! We're running out of time!!","TWN":"菲奧尼副團長！！沒時間了！！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경, 한솔 경! 엄호하세요!","JPN":"アレン卿、ヤガミ卿！　援護を！","ENG":"Dame Liv, Sir Hansol! Cover me!","TWN":"莉芙卿、楊瀚卿！掩護我！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리의 긍지를 위해서라도, 임무를 위해서라도 우리는 여기서 절대 물러설 수 없어요!","JPN":"私たちの誇りのためにも、任務のためにも、絶対ここで引くわけにはいきません！","ENG":"For our pride and for our mission! Retreating is absolutely unacceptable!","TWN":"為了我們的榮譽，或是為了任務也好，我們都絕對不能輸！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>무구</color>를 개방하겠습니다!","JPN":"<color=#ffd34c>武具</color>を開放します！","ENG":"I am going to unleash my <color=#ffd34c>Armament</color>!","TWN":"我要開放<color=#ffd34c>武具</color>！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐어!? 그건 너무 위험하지 않아!?","JPN":"はあ！？　それ、ヤバすぎない！？","ENG":"What?! But isn't that too dangerous?!","TWN":"什麼！？這樣不會太危險嗎！？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최대한 파괴력을 억누르는데 집중할 겁니다! 그러기 위해선 시간이 필요해요!","JPN":"なるべく破壊力を抑えるのに集中します！　そのためには、時間が必要です！","ENG":"I'm going to focus all my powers on suppressing its destructiveness! But I will need time in order to do so!","TWN":"我會盡可能控制破壞力！所以我需要時間！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"정말 그래도 괜찮아? 아무리 억누른다고 해도, 카운터가 아니면 다칠지도 몰라!","JPN":"本当にそれでいいの？　いくら抑えるっていっても、カウンターじゃないと怪我するかもしれないんだよ！？","ENG":"Are you sure about this? Even if you suppress it, non-Counters might get hurt!","TWN":"真的沒關係嗎？不管怎麼控制，對方若不是制裁者很可能會受傷吧？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저 팀에는 카운터가 아닌 아이도 끼어 있다구!","JPN":"あのチームには、カウンターじゃない子もいる！","ENG":"There are non-Counters on the other team, you know!","TWN":"對方的隊伍裡也有不是制裁者的人欸！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브경, 이제까지 계속 버텨온 방패가 바로 그 아이입니다!","JPN":"アレン卿、今までずっと持ちこたえてきた盾がその子なのです！","ENG":"Dame Liv, that non-Counter is the shield that withstood all our attacks so far!","TWN":"莉芙卿，一直拿著盾牌誓死抵抗的就是那個孩子！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최선을 다한 상대에게 부끄러운 승리를 넘겨주는 것은…… 기사단의 수치!","JPN":"最善を尽くした相手に恥ずかしい勝利を渡すのは……騎士団の恥！","ENG":"Handing over a shameful victory to an opponent who did their best... That is a disgrace to the Knights!","TWN":"她這麼努力，我要是將勝利就這樣拱手讓給她……這是身為騎士的羞恥！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"모두 조심하세요! 상대 측 리더가 뭔가를 준비하고 있습니다!","JPN":"みなさん、気をつけてください！　相手側のリーダーが何かを準備しています！","ENG":"Look alive, everyone! Their leader is preparing something!","TWN":"大家小心！對方的隊長好像預備要做什麼！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런……! 꼬마 대장! 큰게 온다! 어서 뒤로 빠져!","JPN":"まずいぞ……！　チビ隊長！　何かが来る！　早く後ろに下がれ！","ENG":"Oh, bollocks...! Little Captain! Get back, now! Something big's coming!","TWN":"糟糕……！小不點隊長！有一波大的要來了！快退到後面！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 돼요! 디펜더인 제가 물러서면 바로 전열이 뚫린다고요!","JPN":"ダメです！　ディフェンダーの私が下がったら、すぐに突破されます！","ENG":"No! I'm the defender! If I don't stand my ground, then it's game over!","TWN":"不可以！我是負責防守的，要是我撤退的話，會立刻被攻破的！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};